mapper.update:
update t_r_mcp_token_scope_grant
set status = 'ACTIVE',
    activated_at = #{activatedAt},
    activated_by_user_id = #{activatedByUserId}
where id = #{id}
  and status = 'PENDING_APPROVAL'

update t_r_mcp_token_scope_grant
set status = 'REVOKED',
    revoked_at = #{revokedAt},
    revoked_reason = #{revokedReason}
where id = #{id}
  and status != 'REVOKED'

update t_r_mcp_token_scope_grant
set status = 'REVOKED',
    revoked_at = #{revokedAt},
    revoked_reason = #{revokedReason}
where token_id = #{tokenId}
  and status != 'REVOKED'
